{"type":"html","content":"<style>
  :root{
    --gbmp-bg0:#041a16;
    --gbmp-bg1:#063a2e;
    --gbmp-yellow:#f4cf00;
    --gbmp-white:rgba(255,255,255,.98);
    --gbmp-muted:rgba(255,255,255,.86);
    --gbmp-border:rgba(255,255,255,.18);
    --gbmp-shadow:0 26px 80px rgba(0,0,0,.45);
  }

  .gbm-panels-wrap{
    width:100%;
    height:100%;
    display:flex;
    align-items:stretch;
    padding:44px;
    box-sizing:border-box;
    font-family:system-ui,-apple-system,Segoe UI,Roboto,Arial,sans-serif;
    color:var(--gbmp-white);
  }

  .gbm-panels-card{
    width:100%;
    height:100%;
    border-radius:28px;
    overflow:hidden;
    position:relative;
    box-shadow:var(--gbmp-shadow);
    border:1px solid var(--gbmp-border);
    background:
      radial-gradient(1200px 760px at 18% 18%, rgba(11,122,92,.28), transparent 62%),
      radial-gradient(1050px 760px at 86% 10%, rgba(244,207,0,.18), transparent 64%),
      linear-gradient(135deg, var(--gbmp-bg0), var(--gbmp-bg1));
  }

  .gbm-panels-card::before{
    content:"";
    position:absolute;inset:0;
    background:
      linear-gradient(120deg, rgba(255,255,255,.06), transparent 40%),
      repeating-linear-gradient(135deg, rgba(255,255,255,.05) 0 1px, transparent 1px 12px);
    opacity:.18;
    pointer-events:none;
  }

  .gbm-panels-inner{
    position:relative;
    width:100%;
    height:100%;
    padding:36px 44px;
    box-sizing:border-box;
    display:grid;
    grid-template-rows:auto auto 1fr auto;
    gap:18px;
  }

  .gbm-panels-header{
    display:flex;
    align-items:flex-start;
    justify-content:space-between;
    gap:22px;
  }

  .gbm-panels-title{
    font-size:52px;
    font-weight:950;
    line-height:1.05;
    margin:0 0 6px;
  }

  .gbm-panels-sub{
    margin:0;
    font-size:22px;
    font-weight:700;
    color:var(--gbmp-muted);
    line-height:1.3;
  }

  .gbm-panels-badge{
    display:inline-flex;
    align-items:center;
    gap:10px;
    padding:14px 20px;
    border-radius:999px;
    background:rgba(244,207,0,.96);
    color:#111;
    font-weight:950;
    font-size:18px;
    letter-spacing:1px;
    text-transform:uppercase;
    box-shadow:0 14px 34px rgba(0,0,0,.22);
    white-space:nowrap;
    flex-shrink:0;
  }

  .gbm-panels-badge .dot{
    width:12px;height:12px;
    border-radius:999px;
    background:#0b7a5c;
    box-shadow:0 0 0 5px rgba(11,122,92,.25);
  }

  .gbm-panels-stats{
    display:grid;
    grid-template-columns:repeat(4,1fr);
    gap:14px;
  }

  .gbm-panels-stat{
    background:rgba(255,255,255,.10);
    border:1px solid rgba(255,255,255,.16);
    border-radius:16px;
    padding:16px 22px;
    box-sizing:border-box;
  }

  .gbm-panels-stat-val{
    font-size:38px;
    font-weight:950;
    line-height:1;
    margin-bottom:4px;
  }

  .gbm-bought{color:var(--gbmp-yellow);}
  .gbm-sep{color:rgba(255,255,255,.3);font-weight:400;margin:0 3px;}
  .gbm-total{color:rgba(255,255,255,.45);font-size:28px;}

  .gbm-panels-stat-label{
    font-size:13px;
    font-weight:700;
    color:rgba(255,255,255,.6);
    text-transform:uppercase;
    letter-spacing:.05em;
  }

  .gbm-panels-main{
    display:grid;
    grid-template-columns:1fr 200px;
    gap:18px;
    min-height:0;
  }

  .gbm-panels-grid-wrap{
    display:flex;
    flex-direction:column;
    gap:12px;
    min-height:0;
  }

  .gbm-panels-legend{
    display:flex;gap:20px;align-items:center;flex-shrink:0;
  }

  .gbm-panels-legend-item{
    display:flex;align-items:center;gap:8px;
    font-size:17px;font-weight:700;
    color:rgba(255,255,255,.75);
  }

  .gbm-panels-swatch{
    width:24px;height:15px;border-radius:4px;flex-shrink:0;
  }

  .gbm-swatch-bought{
    background:var(--gbmp-yellow);
    box-shadow:0 0 0 3px rgba(244,207,0,.2);
  }

  .gbm-swatch-partial{
    background:linear-gradient(to right, #f9dd2a 17%, rgba(255,255,255,.10) 17%);
    border:1px solid rgba(244,207,0,.4);
  }

  .gbm-swatch-available{
    background:rgba(255,255,255,.12);
    border:1px solid rgba(255,255,255,.22);
  }

  .gbm-panels-grid{
    display:grid;
    grid-template-columns:repeat(8,1fr);
    grid-template-rows:repeat(8,1fr);
    gap:6px;
    flex:1;
    min-height:0;
  }

  .gbm-panel{
    border-radius:5px;
    position:relative;
    cursor:default;
    transition:transform .15s ease;
    min-height:0;
    overflow:hidden;
  }

  .gbm-panel:hover{transform:scale(1.08);z-index:2;}

  .gbm-panel-bought{
    background:linear-gradient(135deg,#f9dd2a 0%,#dfb700 100%);
    box-shadow:0 2px 10px rgba(244,207,0,.5);
    animation:gbmPop .3s ease both;
  }

  .gbm-panel-partial{
    background:rgba(255,255,255,.06);
    border:1px solid rgba(244,207,0,.55);
    box-shadow:0 0 10px rgba(244,207,0,.18);
  }

  .gbm-panel-partial-fill{
    position:absolute;
    bottom:0; left:0; right:0;
    background:linear-gradient(to top, #dfb700 0%, #f9dd2a 100%);
    opacity:0.9;
  }

  .gbm-panel-partial-label{
    position:absolute;
    inset:0;
    display:flex;
    align-items:center;
    justify-content:center;
    font-size:9px;
    font-weight:900;
    color:#fff;
    z-index:2;
    text-shadow:0 1px 4px rgba(0,0,0,.7);
    letter-spacing:.02em;
  }

  .gbm-panel-available{
    background:rgba(255,255,255,.08);
    border:1px solid rgba(255,255,255,.14);
  }

  .gbm-panel::before{
    content:'';
    position:absolute;
    inset:2px;
    border-radius:3px;
    background-image:
      linear-gradient(to right,rgba(255,255,255,.18) 1px,transparent 1px),
      linear-gradient(to bottom,rgba(255,255,255,.18) 1px,transparent 1px);
    background-size:33.3% 50%;
    z-index:1;
    pointer-events:none;
  }

  .gbm-panel:hover::after{
    content:attr(data-tip);
    position:absolute;
    bottom:calc(100% + 4px);
    left:50%;
    transform:translateX(-50%);
    background:rgba(0,0,0,.85);
    color:#fff;
    font-size:11px;
    font-weight:700;
    padding:3px 7px;
    border-radius:4px;
    white-space:nowrap;
    pointer-events:none;
    z-index:10;
  }

  @keyframes gbmPop{
    0%{transform:scale(.4);opacity:0;}
    70%{transform:scale(1.1);}
    100%{transform:scale(1);opacity:1;}
  }

  .gbm-panels-sidebar{
    display:flex;
    flex-direction:column;
    gap:14px;
    min-height:0;
  }

  .gbm-panels-qr-box{
    background:rgba(255,255,255,.10);
    border:1px solid rgba(255,255,255,.18);
    border-radius:18px;
    padding:16px;
    display:flex;
    flex-direction:column;
    align-items:center;
    gap:10px;
    flex:1;
    min-height:0;
  }

  .gbm-panels-qr-title{
    font-size:13px;
    font-weight:800;
    text-transform:uppercase;
    letter-spacing:.06em;
    color:rgba(255,255,255,.65);
  }

  .gbm-panels-qr-canvas-wrap{
    background:#fff;
    border-radius:10px;
    padding:8px;
    width:100%;
    aspect-ratio:1/1;
    display:flex;
    align-items:center;
    justify-content:center;
    flex-shrink:0;
  }

  .gbm-panels-qr-img{
    display:block;
    width:100%;
    height:100%;
    object-fit:contain;
  }

  .gbm-panels-header-url{
    font-size:15px;
    font-weight:800;
    color:var(--gbmp-yellow);
    text-align:right;
    margin-top:8px;
  }

  .gbm-panels-donate-box{
